// Trainer View
const TrainerBatchView = ({ 
  user, batches, users, attendance, onMarkAttendance, tasks, onAddTask 
}: { 
  user: User, 
  batches: Batch[], 
  users: User[],
  attendance: AttendanceRecord[],
  onMarkAttendance: (batchId: string, studentId: string, status: 'PRESENT' | 'ABSENT') => void,
  tasks: Task[],
  onAddTask: (task: Task) => void
}) => {
  const myBatches = batches.filter(b => b.trainerId === user.id);
  const [selectedBatch, setSelectedBatch] = useState<Batch | null>(myBatches[0] || null);

  // Task Form State
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskDesc, setNewTaskDesc] = useState('');

  const handleCreateTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBatch) return;
    const newTask: Task = {
      id: `t${Date.now()}`,
      batchId: selectedBatch.id,
      title: newTaskTitle,
      description: newTaskDesc,
      dueDate: new Date().toISOString().split('T')[0],
      assignedBy: user.id
    };
    onAddTask(newTask);
    setNewTaskTitle('');
    setNewTaskDesc('');
  };

  if (!selectedBatch) return <div className="text-center py-20 text-gray-500">No batches assigned.</div>;

  const batchStudents = users.filter(u => selectedBatch.studentIds.includes(u.id));

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row gap-4 md:items-center justify-between">
        <div>
           <h2 className="text-2xl font-bold text-gray-800">My Classes</h2>
           <p className="text-gray-500">Manage attendance and tasks</p>
        </div>
        <select 
          className="border border-gray-300 rounded-lg px-4 py-2 bg-white text-gray-700 focus:outline-none focus:ring-2 focus:ring-indigo-500"
          value={selectedBatch.id}
          onChange={(e) => setSelectedBatch(myBatches.find(b => b.id === e.target.value) || null)}
        >
          {myBatches.map(b => (
            <option key={b.id} value={b.id}>{b.name} ({b.schedule})</option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Attendance Card */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
            <UserCheck className="w-5 h-5 text-indigo-600" />
            Mark Attendance ({new Date().toLocaleDateString()})
          </h3>
          <div className="space-y-3">
            {batchStudents.map(student => {
              // Check if already marked for today (simplified check for demo)
              const record = attendance.find(a => 
                a.batchId === selectedBatch.id && 
                a.studentId === student.id && 
                a.date === new Date().toISOString().split('T')[0] // simplistic date check
              );

              return (
                <div key={student.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center gap-3">
                    <img src={student.avatar} alt="" className="w-8 h-8 rounded-full" />
                    <span className="font-medium text-gray-700">{student.name}</span>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => onMarkAttendance(selectedBatch.id, student.id, 'PRESENT')}
                      className={`px-3 py-1 rounded text-sm font-medium transition-colors ${
                        record?.status === 'PRESENT' 
                          ? 'bg-green-100 text-green-700 border border-green-200' 
                          : 'bg-white border border-gray-200 text-gray-500 hover:bg-gray-100'
                      }`}
                    >
                      Present
                    </button>
                    <button 
                      onClick={() => onMarkAttendance(selectedBatch.id, student.id, 'ABSENT')}
                      className={`px-3 py-1 rounded text-sm font-medium transition-colors ${
                        record?.status === 'ABSENT' 
                          ? 'bg-red-100 text-red-700 border border-red-200' 
                          : 'bg-white border border-gray-200 text-gray-500 hover:bg-gray-100'
                      }`}
                    >
                      Absent
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Task Assignment */}
