    : 100;

  return (
    <div className="space-y-6">
       <div className="bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl p-8 text-white shadow-lg">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-4">
              <img src={user.avatar} className="w-16 h-16 rounded-full border-4 border-white/20" alt="" />
              <div>
                <h2 className="text-2xl font-bold">Hello, {user.name}!</h2>
                <p className="text-indigo-100">Student • {myBatches.length > 0 ? myBatches[0].course : 'No Course'}</p>
              </div>
            </div>
            <div className="bg-white/10 backdrop-blur-sm p-4 rounded-xl flex gap-8">
              <div>
                <p className="text-xs text-indigo-100 uppercase tracking-wide">Attendance</p>
                <p className="text-2xl font-bold">{attendanceRate}%</p>
              </div>
              <div>
                <p className="text-xs text-indigo-100 uppercase tracking-wide">Assignments</p>
                <p className="text-2xl font-bold">{myTasks.length}</p>
              </div>
            </div>
          </div>
       </div>

       <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
            <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
              <CheckSquare className="w-5 h-5 text-indigo-600" /> Pending Tasks
