              {myTasks.map(task => {
                const submission = submissions.find(s => s.taskId === task.id && s.studentId === user.id);
                return (
                  <div key={task.id} className="border border-gray-100 p-4 rounded-lg hover:border-indigo-200 transition-colors">
                    <div className="flex justify-between items-start mb-2">
                      <h4 className="font-semibold text-gray-800">{task.title}</h4>
                      {submission ? (
                        <span className="bg-green-100 text-green-700 text-xs px-2 py-1 rounded font-medium flex items-center gap-1">
                          <CheckCircle className="w-3 h-3" /> Done
