                      ) : (
                        <span className="bg-yellow-100 text-yellow-700 text-xs px-2 py-1 rounded font-medium">Pending</span>
                      )}
                    </div>
                    <p className="text-sm text-gray-600 mb-3">{task.description}</p>
                    <div className="flex justify-between items-center text-xs text-gray-500">
                       <span>Due: {task.dueDate}</span>
                       {submission?.grade && <span className="font-bold text-indigo-600">Grade: {submission.grade}/100</span>}
                    </div>
                  </div>
                );
              })}
              {myTasks.length === 0 && <p className="text-gray-400">No active tasks.</p>}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
             <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
              <Calendar className="w-5 h-5 text-indigo-600" /> Recent Attendance
