const TrainerAttendanceView = ({ 
  user, batches, users, attendance, onMarkAttendance 
}: { 
  user: User, batches: Batch[], users: User[], attendance: AttendanceRecord[], onMarkAttendance: (b: string, s: string, st: 'PRESENT' | 'ABSENT') => void 
}) => {
  const myBatches = batches.filter(b => b.trainerId === user.id);
  const [selectedBatchId, setSelectedBatchId] = useState<string>(myBatches[0]?.id || '');

  const selectedBatch = myBatches.find(b => b.id === selectedBatchId);
  if (!selectedBatch) return <div className="text-center py-10">No batches assigned.</div>;

  const batchStudents = users.filter(u => selectedBatch.studentIds.includes(u.id));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800">Attendance Manager</h2>
        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-gray-600">Select Batch:</label>
          <select 
            className="border border-gray-300 rounded-lg px-4 py-2 bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
            value={selectedBatchId}
            onChange={(e) => setSelectedBatchId(e.target.value)}
          >
            {myBatches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex justify-between items-center">
           <h3 className="font-semibold text-gray-700">Date: {new Date().toLocaleDateString()}</h3>
           <span className="text-sm text-gray-500">{batchStudents.length} Students Enrolled</span>
        </div>
        <div className="divide-y divide-gray-100">
          {batchStudents.map(student => {
             const record = attendance.find(a => 
                a.batchId === selectedBatch.id && 
                a.studentId === student.id && 
                a.date === new Date().toISOString().split('T')[0]
             );
             return (
               <div key={student.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                  <div className="flex items-center gap-3">
                    <img src={student.avatar} alt="" className="w-10 h-10 rounded-full bg-gray-200" />
                    <div>
                      <p className="font-medium text-gray-800">{student.name}</p>
                      <p className="text-xs text-gray-500">{student.email}</p>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => onMarkAttendance(selectedBatch.id, student.id, 'PRESENT')}
                      className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                        record?.status === 'PRESENT' 
                          ? 'bg-green-600 text-white shadow-md' 
                          : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                    >
                      Present
                    </button>
                    <button 
                      onClick={() => onMarkAttendance(selectedBatch.id, student.id, 'ABSENT')}
                      className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                        record?.status === 'ABSENT' 
                          ? 'bg-red-600 text-white shadow-md' 
                          : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                    >
                      Absent
                    </button>
                  </div>
               </div>
             );
          })}
        </div>
      </div>
    </div>
  );
};

const TrainerTasksView = ({ 
  user, batches, tasks, onAddTask 
}: { 
  user: User, batches: Batch[], tasks: Task[], onAddTask: (t: Task) => void 
}) => {
  const myBatches = batches.filter(b => b.trainerId === user.id);
  const [showForm, setShowForm] = useState(false);
  const [selectedBatchId, setSelectedBatchId] = useState<string>(myBatches[0]?.id || '');
  const [newTask, setNewTask] = useState({ title: '', desc: '', date: '' });

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBatchId) return;
    onAddTask({
      id: `t${Date.now()}`,
      batchId: selectedBatchId,
      title: newTask.title,
      description: newTask.desc,
      dueDate: newTask.date || new Date().toISOString().split('T')[0],
      assignedBy: user.id
    });
    setNewTask({ title: '', desc: '', date: '' });
    setShowForm(false);
  };

  const myTasks = tasks.filter(t => myBatches.some(b => b.id === t.batchId));

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">Task Management</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition-colors"
        >
          {showForm ? <XCircle className="w-4 h-4" /> : <Plus className="w-4 h-4" />}
          {showForm ? 'Cancel' : 'Create Task'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-md border border-indigo-100 animate-in fade-in slide-in-from-top-4">
           <h3 className="font-bold text-gray-800 mb-4">New Assignment Details</h3>
           <form onSubmit={handleCreate} className="space-y-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Target Batch</label>
                 <select 
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 bg-white"
                    value={selectedBatchId}
                    onChange={(e) => setSelectedBatchId(e.target.value)}
                 >
                   {myBatches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                 </select>
               </div>
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Due Date</label>
                 <input 
                    type="date"
                    required
                    className="w-full border border-gray-300 rounded-lg px-3 py-2"
                    value={newTask.date}
                    onChange={(e) => setNewTask({...newTask, date: e.target.value})}
                 />
               </div>
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Task Title</label>
                <input 
                  type="text"
                  required
                  placeholder="e.g. REST API Implementation"
                  className="w-full border border-gray-300 rounded-lg px-3 py-2"
                  value={newTask.title}
                  onChange={(e) => setNewTask({...newTask, title: e.target.value})}
                />
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea 
                  required
                  placeholder="Detailed instructions..."
