const TrainerGradingView = ({ 
  user, tasks, submissions, users, onGrade 
}: { 
  user: User, tasks: Task[], submissions: Submission[], users: User[], onGrade: (id: string, g: number, f: string) => void 
}) => {
  const [selectedTaskId, setSelectedTaskId] = useState<string>('');
  const [gradingState, setGradingState] = useState<{ [key: string]: { grade: string, feedback: string, generating: boolean } }>({});

  // Tasks created by this trainer
  const myTasks = tasks.filter(t => t.assignedBy === user.id);

  // Set default selected task
  useEffect(() => {
    if (myTasks.length > 0 && !selectedTaskId) {
      setSelectedTaskId(myTasks[0].id);
    }
  }, [myTasks, selectedTaskId]);

  const currentTask = myTasks.find(t => t.id === selectedTaskId);

  // Find submissions for the selected task
  const relevantSubmissions = submissions.filter(s => s.taskId === selectedTaskId);

  const handleAiFeedback = async (submissionId: string, studentName: string, gradeStr: string) => {
    const grade = parseInt(gradeStr);
    if (isNaN(grade)) return;

    setGradingState(prev => ({ 
      ...prev, 
      [submissionId]: { ...prev[submissionId], generating: true } 
    }));

    const feedback = await generateTaskFeedback(currentTask?.title || 'Assignment', studentName, grade);

    setGradingState(prev => ({ 
      ...prev, 
      [submissionId]: { 
        ...prev[submissionId], 
        feedback, 
        generating: false 
      } 
    }));
  };

  const handleSave = (submissionId: string) => {
    const state = gradingState[submissionId];
    if (state && state.grade) {
      onGrade(submissionId, parseInt(state.grade), state.feedback || '');
      // Clear local state after save if needed, or keep it to show current values
    }
  };

  const handleInputChange = (id: string, field: 'grade' | 'feedback', value: string) => {
    setGradingState(prev => ({
        ...prev,
        [id]: { ...prev[id], [field]: value }
    }));
  };

  return (
    <div className="space-y-6">
       <h2 className="text-2xl font-bold text-gray-800">Student Grading</h2>

       <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
          <label className="font-medium text-gray-700">Select Assignment:</label>
          <select 
             className="border border-gray-300 rounded-lg px-3 py-2 bg-white flex-1 max-w-md"
             value={selectedTaskId}
             onChange={(e) => setSelectedTaskId(e.target.value)}
          >
             {myTasks.map(t => <option key={t.id} value={t.id}>{t.title} (Due: {t.dueDate})</option>)}
          </select>
       </div>

       <div className="grid gap-4">
         {relevantSubmissions.map(submission => {
           const student = users.find(u => u.id === submission.studentId);
           const localState = gradingState[submission.id] || { grade: submission.grade?.toString() || '', feedback: submission.feedback || '' };

           return (
             <div key={submission.id} className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex flex-col md:flex-row gap-6">
                <div className="md:w-1/4">
                   <div className="flex items-center gap-3 mb-2">
                      <img src={student?.avatar} className="w-10 h-10 rounded-full" alt="" />
                      <div>
                        <p className="font-bold text-gray-800">{student?.name}</p>
                        <p className="text-xs text-gray-500">Submitted: {new Date(submission.submittedAt).toLocaleDateString()}</p>
                      </div>
                   </div>
                   {submission.grade ? (
                     <span className="bg-green-100 text-green-700 text-xs px-2 py-1 rounded font-bold">Graded: {submission.grade}/100</span>
                   ) : (
                     <span className="bg-yellow-100 text-yellow-700 text-xs px-2 py-1 rounded font-bold">Pending Grading</span>
                   )}
                </div>

                <div className="flex-1 grid gap-4">
                   <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Score (0-100)</label>
                      <input 
                        type="number" 
                        min="0" max="100"
                        className="border border-gray-300 rounded-lg px-3 py-2 w-24"
                        value={localState.grade}
                        onChange={(e) => handleInputChange(submission.id, 'grade', e.target.value)}
                      />
                   </div>
                   <div className="flex-1">
                      <div className="flex justify-between items-center mb-1">
                        <label className="block text-xs font-bold text-gray-500 uppercase">Feedback</label>
                        <button 
                           onClick={() => handleAiFeedback(submission.id, student?.name || 'Student', localState.grade)}
                           disabled={!localState.grade || localState.generating}
                           className="text-xs flex items-center gap-1 text-indigo-600 hover:text-indigo-800 disabled:opacity-50"
                        >
                           <BrainCircuit className="w-3 h-3" />
                           {localState.generating ? 'Generating...' : 'Auto-Generate'}
                        </button>
                      </div>
                      <textarea 
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 h-20 text-sm"
                        placeholder="Enter feedback..."
                        value={localState.feedback}
                        onChange={(e) => handleInputChange(submission.id, 'feedback', e.target.value)}
                      />
                   </div>
                </div>

                <div className="flex items-end">
                   <button 
                     onClick={() => handleSave(submission.id)}
                     className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-indigo-700"
                   >
                     Save Grade
                   </button>
                </div>
             </div>
           );
         })}
         {relevantSubmissions.length === 0 && (
            <div className="text-center py-10 text-gray-500">No submissions found for this task.</div>
         )}
       </div>
    </div>
  );
};

