const SignupPage = ({ onSignup, onSwitchToLogin }: { onSignup: (user: Partial<User>) => void, onSwitchToLogin: () => void }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: '',
    phone: '',
    courseOrExpertise: '' // Course for student, Expertise for trainer
  });
  const [detectedRole, setDetectedRole] = useState<UserRole | null>(null);

  useEffect(() => {
    if (formData.email.endsWith('@admin.edumanage.com')) setDetectedRole(UserRole.ADMIN);
    else if (formData.email.endsWith('@trainer.edumanage.com')) setDetectedRole(UserRole.TRAINER);
    else if (formData.email.includes('@') && formData.email.includes('.')) setDetectedRole(UserRole.STUDENT);
    else setDetectedRole(null);
  }, [formData.email]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (detectedRole && formData.password === formData.confirmPassword) {
       onSignup({
         name: formData.name,
         email: formData.email,
         role: detectedRole,
         // In a real app, backend handles ID and avatar
       });
    }
