const AdminDashboard = ({ 
  users, batches, attendance 
}: { 
  users: User[], batches: Batch[], attendance: AttendanceRecord[] 
}) => {
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  const stats = useMemo(() => {
    const totalStudents = users.filter(u => u.role === UserRole.STUDENT).length;
    const totalTrainers = users.filter(u => u.role === UserRole.TRAINER).length;
    const totalBatches = batches.length;
    const presentCount = attendance.filter(a => a.status === 'PRESENT').length;
    const attendanceRate = attendance.length ? Math.round((presentCount / attendance.length) * 100) : 0;

    return { totalStudents, totalTrainers, totalBatches, attendanceRate };
  }, [users, batches, attendance]);

  const handleGetInsight = async () => {
    setLoadingAi(true);
    const summary = await generateInstituteSummary(stats);
    setAiInsight(summary);
    setLoadingAi(false);
  };

  const chartData = [
    { name: 'Students', value: stats.totalStudents, fill: '#6366f1' },
    { name: 'Trainers', value: stats.totalTrainers, fill: '#a855f7' },
    { name: 'Batches', value: stats.totalBatches, fill: '#ec4899' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Administrator Dashboard</h2>
          <p className="text-gray-500 mt-1">Overview of institute performance</p>
        </div>
        <button 
          onClick={handleGetInsight}
          disabled={loadingAi}
          className="flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-4 py-2 rounded-lg shadow hover:shadow-lg transition-all disabled:opacity-70"
        >
          <BrainCircuit className="w-4 h-4" />
          {loadingAi ? 'Analyzing...' : 'AI Insights'}
        </button>
      </div>

      {aiInsight && (
        <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl flex gap-3 animate-fade-in">
          <BrainCircuit className="w-6 h-6 text-indigo-600 flex-shrink-0 mt-1" />
          <div>
            <h4 className="font-semibold text-indigo-800">AI Executive Summary</h4>
            <p className="text-indigo-700 mt-1 text-sm leading-relaxed">{aiInsight}</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Total Students" value={stats.totalStudents} icon={GraduationCap} color="bg-blue-500" />
        <StatCard label="Total Trainers" value={stats.totalTrainers} icon={Users} color="bg-purple-500" />
        <StatCard label="Active Batches" value={stats.totalBatches} icon={Calendar} color="bg-pink-500" />
        <StatCard label="Avg Attendance" value={`${stats.attendanceRate}%`} icon={UserCheck} color="bg-green-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h3 className="text-lg font-semibold mb-4">Resource Distribution</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip cursor={{fill: 'transparent'}} />
                <Bar dataKey="value" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-center items-center text-center">
            <div className="w-48 h-48 relative">
                 <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie 
                            data={chartData} 
