const TrainerDashboard = ({ user, batches, tasks, submissions }: { user: User, batches: Batch[], tasks: Task[], submissions: Submission[] }) => {
  const myBatches = batches.filter(b => b.trainerId === user.id);
  const myBatchIds = myBatches.map(b => b.id);
  const myTasks = tasks.filter(t => myBatchIds.includes(t.batchId));
  const myTaskIds = myTasks.map(t => t.id);

  // Calculate unique students across all batches
  const studentIds = new Set(myBatches.flatMap(b => b.studentIds));
  const totalStudents = studentIds.size;

  // Count ungraded submissions for my tasks
  const pendingGrading = submissions.filter(s => myTaskIds.includes(s.taskId) && !s.grade).length;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Trainer Dashboard</h2>
          <p className="text-gray-500 mt-1">Manage your classes and students</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="My Batches" value={myBatches.length} icon={Calendar} color="bg-indigo-500" />
        <StatCard label="Total Students" value={totalStudents} icon={Users} color="bg-purple-500" />
        <StatCard label="Active Tasks" value={myTasks.length} icon={ClipboardList} color="bg-blue-500" />
        <StatCard label="Pending Grades" value={pendingGrading} icon={Award} color="bg-orange-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
           <h3 className="font-bold text-gray-800 mb-4">My Schedule</h3>
           <div className="space-y-3">
             {myBatches.map(batch => (
                <div key={batch.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg border border-gray-100">
                   <div>
                      <p className="font-bold text-gray-700">{batch.name}</p>
                      <p className="text-sm text-gray-500">{batch.course}</p>
                   </div>
                   <div className="text-right">
                      <span className="bg-indigo-100 text-indigo-700 text-xs px-2 py-1 rounded font-medium">{batch.schedule}</span>
                   </div>
                </div>
             ))}
           </div>
        </div>
      </div>
    </div>
  );
};

const TrainerAttendanceView = ({ 
  user, batches, users, attendance, onMarkAttendance 
}: { 
  user: User, batches: Batch[], users: User[], attendance: AttendanceRecord[], onMarkAttendance: (b: string, s: string, st: 'PRESENT' | 'ABSENT') => void 
}) => {
  const myBatches = batches.filter(b => b.trainerId === user.id);
  const [selectedBatchId, setSelectedBatchId] = useState<string>(myBatches[0]?.id || '');

  const selectedBatch = myBatches.find(b => b.id === selectedBatchId);
  if (!selectedBatch) return <div className="text-center py-10">No batches assigned.</div>;

  const batchStudents = users.filter(u => selectedBatch.studentIds.includes(u.id));

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-gray-800">Attendance Manager</h2>
        <div className="flex items-center gap-2">
          <label className="text-sm font-medium text-gray-600">Select Batch:</label>
          <select 
            className="border border-gray-300 rounded-lg px-4 py-2 bg-white focus:outline-none focus:ring-2 focus:ring-indigo-500"
            value={selectedBatchId}
            onChange={(e) => setSelectedBatchId(e.target.value)}
          >
            {myBatches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
          </select>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex justify-between items-center">
           <h3 className="font-semibold text-gray-700">Date: {new Date().toLocaleDateString()}</h3>
           <span className="text-sm text-gray-500">{batchStudents.length} Students Enrolled</span>
        </div>
        <div className="divide-y divide-gray-100">
          {batchStudents.map(student => {
             const record = attendance.find(a => 
                a.batchId === selectedBatch.id && 
                a.studentId === student.id && 
                a.date === new Date().toISOString().split('T')[0]
             );
             return (
               <div key={student.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                  <div className="flex items-center gap-3">
                    <img src={student.avatar} alt="" className="w-10 h-10 rounded-full bg-gray-200" />
                    <div>
                      <p className="font-medium text-gray-800">{student.name}</p>
                      <p className="text-xs text-gray-500">{student.email}</p>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => onMarkAttendance(selectedBatch.id, student.id, 'PRESENT')}
                      className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                        record?.status === 'PRESENT' 
                          ? 'bg-green-600 text-white shadow-md' 
                          : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                    >
                      Present
                    </button>
                    <button 
                      onClick={() => onMarkAttendance(selectedBatch.id, student.id, 'ABSENT')}
                      className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
                        record?.status === 'ABSENT' 
                          ? 'bg-red-600 text-white shadow-md' 
                          : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                      }`}
                    >
                      Absent
                    </button>
                  </div>
               </div>
             );
          })}
        </div>
      </div>
    </div>
  );
};

const TrainerTasksView = ({ 
  user, batches, tasks, onAddTask 
}: { 
  user: User, batches: Batch[], tasks: Task[], onAddTask: (t: Task) => void 
}) => {
  const myBatches = batches.filter(b => b.trainerId === user.id);
  const [showForm, setShowForm] = useState(false);
  const [selectedBatchId, setSelectedBatchId] = useState<string>(myBatches[0]?.id || '');
  const [newTask, setNewTask] = useState({ title: '', desc: '', date: '' });

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedBatchId) return;
    onAddTask({
      id: `t${Date.now()}`,
      batchId: selectedBatchId,
      title: newTask.title,
      description: newTask.desc,
      dueDate: newTask.date || new Date().toISOString().split('T')[0],
      assignedBy: user.id
    });
    setNewTask({ title: '', desc: '', date: '' });
    setShowForm(false);
  };

  const myTasks = tasks.filter(t => myBatches.some(b => b.id === t.batchId));

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-gray-800">Task Management</h2>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition-colors"
        >
          {showForm ? <XCircle className="w-4 h-4" /> : <Plus className="w-4 h-4" />}
          {showForm ? 'Cancel' : 'Create Task'}
        </button>
      </div>

      {showForm && (
        <div className="bg-white p-6 rounded-xl shadow-md border border-indigo-100 animate-in fade-in slide-in-from-top-4">
           <h3 className="font-bold text-gray-800 mb-4">New Assignment Details</h3>
           <form onSubmit={handleCreate} className="space-y-4">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Target Batch</label>
                 <select 
                    className="w-full border border-gray-300 rounded-lg px-3 py-2 bg-white"
                    value={selectedBatchId}
                    onChange={(e) => setSelectedBatchId(e.target.value)}
                 >
                   {myBatches.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                 </select>
               </div>
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">Due Date</label>
                 <input 
                    type="date"
                    required
                    className="w-full border border-gray-300 rounded-lg px-3 py-2"
                    value={newTask.date}
                    onChange={(e) => setNewTask({...newTask, date: e.target.value})}
                 />
               </div>
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Task Title</label>
                <input 
                  type="text"
                  required
                  placeholder="e.g. REST API Implementation"
                  className="w-full border border-gray-300 rounded-lg px-3 py-2"
                  value={newTask.title}
                  onChange={(e) => setNewTask({...newTask, title: e.target.value})}
                />
             </div>
             <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea 
                  required
                  placeholder="Detailed instructions..."
                  className="w-full border border-gray-300 rounded-lg px-3 py-2 h-24"
                  value={newTask.desc}
                  onChange={(e) => setNewTask({...newTask, desc: e.target.value})}
                />
             </div>
             <div className="flex justify-end">
                <button type="submit" className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-medium hover:bg-indigo-700">Assign Task</button>
             </div>
           </form>
        </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-gray-50 text-gray-500 font-medium text-xs uppercase tracking-wider">
            <tr>
              <th className="px-6 py-4">Task</th>
              <th className="px-6 py-4">Batch</th>
              <th className="px-6 py-4">Due Date</th>
              <th className="px-6 py-4 text-center">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {myTasks.map(task => {
               const batch = myBatches.find(b => b.id === task.batchId);
               return (
                 <tr key={task.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4">
                       <p className="font-medium text-gray-800">{task.title}</p>
                       <p className="text-xs text-gray-500 truncate max-w-xs">{task.description}</p>
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-600">{batch?.name}</td>
                    <td className="px-6 py-4 text-sm text-gray-600">{task.dueDate}</td>
                    <td className="px-6 py-4 text-center">
                       <span className="bg-green-100 text-green-700 text-xs px-2 py-1 rounded-full font-medium">Active</span>
                    </td>
                 </tr>
               );
            })}
          </tbody>
        </table>
        {myTasks.length === 0 && <div className="p-8 text-center text-gray-500">No tasks created yet.</div>}
      </div>
    </div>
  );
};

const TrainerGradingView = ({ 
  user, tasks, submissions, users, onGrade 
}: { 
  user: User, tasks: Task[], submissions: Submission[], users: User[], onGrade: (id: string, g: number, f: string) => void 
}) => {
  const [selectedTaskId, setSelectedTaskId] = useState<string>('');
  const [gradingState, setGradingState] = useState<{ [key: string]: { grade: string, feedback: string, generating: boolean } }>({});

  // Tasks created by this trainer
  const myTasks = tasks.filter(t => t.assignedBy === user.id);

  // Set default selected task
  useEffect(() => {
    if (myTasks.length > 0 && !selectedTaskId) {
      setSelectedTaskId(myTasks[0].id);
    }
  }, [myTasks, selectedTaskId]);

  const currentTask = myTasks.find(t => t.id === selectedTaskId);

  // Find submissions for the selected task
  const relevantSubmissions = submissions.filter(s => s.taskId === selectedTaskId);

  const handleAiFeedback = async (submissionId: string, studentName: string, gradeStr: string) => {
    const grade = parseInt(gradeStr);
    if (isNaN(grade)) return;

    setGradingState(prev => ({ 
      ...prev, 
      [submissionId]: { ...prev[submissionId], generating: true } 
    }));

    const feedback = await generateTaskFeedback(currentTask?.title || 'Assignment', studentName, grade);

    setGradingState(prev => ({ 
      ...prev, 
      [submissionId]: { 
        ...prev[submissionId], 
        feedback, 
        generating: false 
      } 
    }));
  };

  const handleSave = (submissionId: string) => {
    const state = gradingState[submissionId];
    if (state && state.grade) {
      onGrade(submissionId, parseInt(state.grade), state.feedback || '');
      // Clear local state after save if needed, or keep it to show current values
    }
  };

  const handleInputChange = (id: string, field: 'grade' | 'feedback', value: string) => {
    setGradingState(prev => ({
        ...prev,
        [id]: { ...prev[id], [field]: value }
    }));
  };

  return (
    <div className="space-y-6">
       <h2 className="text-2xl font-bold text-gray-800">Student Grading</h2>

       <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex items-center gap-4">
          <label className="font-medium text-gray-700">Select Assignment:</label>
          <select 
             className="border border-gray-300 rounded-lg px-3 py-2 bg-white flex-1 max-w-md"
             value={selectedTaskId}
             onChange={(e) => setSelectedTaskId(e.target.value)}
          >
             {myTasks.map(t => <option key={t.id} value={t.id}>{t.title} (Due: {t.dueDate})</option>)}
          </select>
       </div>

       <div className="grid gap-4">
         {relevantSubmissions.map(submission => {
           const student = users.find(u => u.id === submission.studentId);
           const localState = gradingState[submission.id] || { grade: submission.grade?.toString() || '', feedback: submission.feedback || '' };

           return (
             <div key={submission.id} className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex flex-col md:flex-row gap-6">
                <div className="md:w-1/4">
                   <div className="flex items-center gap-3 mb-2">
                      <img src={student?.avatar} className="w-10 h-10 rounded-full" alt="" />
                      <div>
                        <p className="font-bold text-gray-800">{student?.name}</p>
                        <p className="text-xs text-gray-500">Submitted: {new Date(submission.submittedAt).toLocaleDateString()}</p>
                      </div>
                   </div>
                   {submission.grade ? (
                     <span className="bg-green-100 text-green-700 text-xs px-2 py-1 rounded font-bold">Graded: {submission.grade}/100</span>
                   ) : (
                     <span className="bg-yellow-100 text-yellow-700 text-xs px-2 py-1 rounded font-bold">Pending Grading</span>
                   )}
                </div>

                <div className="flex-1 grid gap-4">
                   <div>
                      <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Score (0-100)</label>
                      <input 
                        type="number" 
                        min="0" max="100"
                        className="border border-gray-300 rounded-lg px-3 py-2 w-24"
                        value={localState.grade}
                        onChange={(e) => handleInputChange(submission.id, 'grade', e.target.value)}
                      />
                   </div>
                   <div className="flex-1">
                      <div className="flex justify-between items-center mb-1">
                        <label className="block text-xs font-bold text-gray-500 uppercase">Feedback</label>
                        <button 
                           onClick={() => handleAiFeedback(submission.id, student?.name || 'Student', localState.grade)}
                           disabled={!localState.grade || localState.generating}
                           className="text-xs flex items-center gap-1 text-indigo-600 hover:text-indigo-800 disabled:opacity-50"
                        >
                           <BrainCircuit className="w-3 h-3" />
                           {localState.generating ? 'Generating...' : 'Auto-Generate'}
                        </button>
                      </div>
                      <textarea 
                        className="w-full border border-gray-300 rounded-lg px-3 py-2 h-20 text-sm"
                        placeholder="Enter feedback..."
                        value={localState.feedback}
                        onChange={(e) => handleInputChange(submission.id, 'feedback', e.target.value)}
                      />
                   </div>
                </div>

                <div className="flex items-end">
                   <button 
                     onClick={() => handleSave(submission.id)}
                     className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-indigo-700"
                   >
                     Save Grade
                   </button>
                </div>
             </div>
           );
         })}
         {relevantSubmissions.length === 0 && (
            <div className="text-center py-10 text-gray-500">No submissions found for this task.</div>
         )}
       </div>
    </div>
  );
};

// Student View

const StudentDashboard = ({ 
  user, batches, tasks, attendance, submissions 
}: { 
  user: User, batches: Batch[], tasks: Task[], attendance: AttendanceRecord[], submissions: Submission[] 
}) => {
  const myBatches = batches.filter(b => b.studentIds.includes(user.id));
  const myBatchIds = myBatches.map(b => b.id);
  const myTasks = tasks.filter(t => myBatchIds.includes(t.batchId));
  const myAttendance = attendance.filter(a => a.studentId === user.id);

  const attendanceRate = myAttendance.length > 0 
    ? Math.round((myAttendance.filter(a => a.status === 'PRESENT').length / myAttendance.length) * 100) 
    : 100;

  return (
    <div className="space-y-6">
       <div className="bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl p-8 text-white shadow-lg">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
            <div className="flex items-center gap-4">
              <img src={user.avatar} className="w-16 h-16 rounded-full border-4 border-white/20" alt="" />
              <div>
                <h2 className="text-2xl font-bold">Hello, {user.name}!</h2>
                <p className="text-indigo-100">Student • {myBatches.length > 0 ? myBatches[0].course : 'No Course'}</p>
              </div>
            </div>
            <div className="bg-white/10 backdrop-blur-sm p-4 rounded-xl flex gap-8">
              <div>
                <p className="text-xs text-indigo-100 uppercase tracking-wide">Attendance</p>
                <p className="text-2xl font-bold">{attendanceRate}%</p>
              </div>
              <div>
                <p className="text-xs text-indigo-100 uppercase tracking-wide">Assignments</p>
                <p className="text-2xl font-bold">{myTasks.length}</p>
              </div>
            </div>
          </div>
       </div>

       <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
            <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
              <CheckSquare className="w-5 h-5 text-indigo-600" /> Pending Tasks
            </h3>
            <div className="space-y-3">
              {myTasks.filter(task => !submissions.some(s => s.taskId === task.id && s.studentId === user.id)).slice(0, 3).map(task => (
                  <div key={task.id} className="border border-gray-100 p-4 rounded-lg hover:border-indigo-200 transition-colors">
                    <div className="flex justify-between items-start mb-2">
                      <h4 className="font-semibold text-gray-800">{task.title}</h4>
                      <span className="bg-yellow-100 text-yellow-700 text-xs px-2 py-1 rounded font-medium">Pending</span>
                    </div>
                    <p className="text-sm text-gray-600 mb-3 truncate">{task.description}</p>
                    <div className="flex justify-between items-center text-xs text-gray-500">
                       <span>Due: {task.dueDate}</span>
                    </div>
                  </div>
              ))}
              {myTasks.filter(task => !submissions.some(s => s.taskId === task.id && s.studentId === user.id)).length === 0 && <p className="text-gray-400">No pending tasks.</p>}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
             <h3 className="font-bold text-gray-800 mb-4 flex items-center gap-2">
              <Calendar className="w-5 h-5 text-indigo-600" /> Recent Attendance
            </h3>
            <div className="space-y-2">
              {myAttendance.slice(0, 5).map(record => (
                <div key={record.id} className="flex justify-between items-center p-3 bg-gray-50 rounded-lg">
                  <span className="text-sm font-medium text-gray-700">{record.date}</span>
                  <span className={`text-xs font-bold px-2 py-1 rounded ${
                    record.status === 'PRESENT' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                  }`}>
                    {record.status}
                  </span>
                </div>
              ))}
              {myAttendance.length === 0 && <p className="text-gray-400">No attendance records found.</p>}
            </div>
          </div>
       </div>
    </div>
  );
};

