                  <p className="text-gray-600 mb-4">{task.description}</p>
                  <div className="flex items-center gap-4 text-sm text-gray-500">
                    <span className="flex items-center gap-1"><Clock className="w-4 h-4" /> Due: {task.dueDate}</span>
                    {submission && (
                       <span className="flex items-center gap-1 text-green-600"><CheckCircle className="w-4 h-4" /> Submitted on {new Date(submission.submittedAt).toLocaleDateString()}</span>
