  );
};

const StudentAttendanceView = ({ 
  user, attendance, batches 
}: { 
  user: User, attendance: AttendanceRecord[], batches: Batch[] 
}) => {
  const myAttendance = attendance.filter(a => a.studentId === user.id);
  // Sort by date descending
  const sortedAttendance = [...myAttendance].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const stats = useMemo(() => {
     const total = myAttendance.length;
