const StudentAttendanceView = ({ 
  user, attendance, batches 
}: { 
  user: User, attendance: AttendanceRecord[], batches: Batch[] 
}) => {
  const myAttendance = attendance.filter(a => a.studentId === user.id);
  // Sort by date descending
  const sortedAttendance = [...myAttendance].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  const stats = useMemo(() => {
     const total = myAttendance.length;
     const present = myAttendance.filter(a => a.status === 'PRESENT').length;
     const percentage = total > 0 ? Math.round((present / total) * 100) : 100;
     return { total, present, percentage };
  }, [myAttendance]);

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-800">My Attendance History</h2>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
