            <div>
               <p className="text-gray-500 text-sm">Overall Attendance</p>
               <p className="text-2xl font-bold text-indigo-600">{stats.percentage}%</p>
            </div>
            <div className="bg-indigo-50 p-2 rounded-full"><UserCheck className="w-6 h-6 text-indigo-600" /></div>
         </div>
         <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex items-center justify-between">
            <div>
               <p className="text-gray-500 text-sm">Classes Attended</p>
               <p className="text-2xl font-bold text-green-600">{stats.present}</p>
            </div>
            <div className="bg-green-50 p-2 rounded-full"><CheckCircle className="w-6 h-6 text-green-600" /></div>
         </div>
         <div className="bg-white p-4 rounded-xl border border-gray-200 shadow-sm flex items-center justify-between">
            <div>
               <p className="text-gray-500 text-sm">Classes Missed</p>
               <p className="text-2xl font-bold text-red-600">{stats.total - stats.present}</p>
            </div>
            <div className="bg-red-50 p-2 rounded-full"><XCircle className="w-6 h-6 text-red-600" /></div>
