const AdminDashboard = ({ 
  users, batches, attendance 
}: { 
  users: User[], batches: Batch[], attendance: AttendanceRecord[] 
}) => {
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  const stats = useMemo(() => {
    const totalStudents = users.filter(u => u.role === UserRole.STUDENT).length;
    const totalTrainers = users.filter(u => u.role === UserRole.TRAINER).length;
    const totalBatches = batches.length;
    const presentCount = attendance.filter(a => a.status === 'PRESENT').length;
    const attendanceRate = attendance.length ? Math.round((presentCount / attendance.length) * 100) : 0;

    return { totalStudents, totalTrainers, totalBatches, attendanceRate };
  }, [users, batches, attendance]);

  const handleGetInsight = async () => {
    setLoadingAi(true);
    const summary = await generateInstituteSummary(stats);
    setAiInsight(summary);
    setLoadingAi(false);
  };

  const chartData = [
    { name: 'Students', value: stats.totalStudents, fill: '#6366f1' },
    { name: 'Trainers', value: stats.totalTrainers, fill: '#a855f7' },
    { name: 'Batches', value: stats.totalBatches, fill: '#ec4899' },
  ];

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Administrator Dashboard</h2>
          <p className="text-gray-500 dark:text-gray-400 mt-1">Overview of institute performance</p>
        </div>
        <button 
          onClick={handleGetInsight}
          disabled={loadingAi}
          className="flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-purple-600 text-white px-4 py-2 rounded-lg shadow hover:shadow-lg transition-all disabled:opacity-70"
        >
          <BrainCircuit className="w-4 h-4" />
          {loadingAi ? 'Analyzing...' : 'AI Insights'}
        </button>
      </div>

      {aiInsight && (
        <div className="bg-indigo-50 dark:bg-indigo-900/30 border border-indigo-100 dark:border-indigo-800 p-4 rounded-xl flex gap-3 animate-fade-in">
          <BrainCircuit className="w-6 h-6 text-indigo-600 dark:text-indigo-400 flex-shrink-0 mt-1" />
          <div>
            <h4 className="font-semibold text-indigo-800 dark:text-indigo-300">AI Executive Summary</h4>
            <p className="text-indigo-700 dark:text-indigo-200 mt-1 text-sm leading-relaxed">{aiInsight}</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Total Students" value={stats.totalStudents} icon={GraduationCap} color="bg-blue-500" />
        <StatCard label="Total Trainers" value={stats.totalTrainers} icon={Users} color="bg-purple-500" />
        <StatCard label="Active Batches" value={stats.totalBatches} icon={Calendar} color="bg-pink-500" />
        <StatCard label="Avg Attendance" value={`${stats.attendanceRate}%`} icon={UserCheck} color="bg-green-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-gray-800 p-6 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700">
          <h3 className="text-lg font-semibold mb-4 text-gray-800 dark:text-gray-100">Resource Distribution</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#374151" />
                <XAxis dataKey="name" stroke="#9CA3AF" />
                <YAxis stroke="#9CA3AF" />
                <Tooltip 
                  cursor={{fill: 'transparent'}} 
                  contentStyle={{ backgroundColor: '#1F2937', borderColor: '#374151', color: '#F3F4F6' }}
                />
                <Bar dataKey="value" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 p-6 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 flex flex-col justify-center items-center text-center">
            <div className="w-48 h-48 relative">
                 <ResponsiveContainer width="100%" height="100%">
                    <PieChart>
                        <Pie 
                            data={chartData} 
                            innerRadius={60} 
                            outerRadius={80} 
                            paddingAngle={5} 
                            dataKey="value"
                        >
                            {chartData.map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={entry.fill} />
                            ))}
                        </Pie>
                        <Tooltip contentStyle={{ backgroundColor: '#1F2937', borderColor: '#374151', color: '#F3F4F6' }} />
                    </PieChart>
                 </ResponsiveContainer>
                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                     <span className="text-2xl font-bold text-gray-700 dark:text-gray-200">{users.length}</span>
                 </div>
            </div>
            <p className="mt-4 text-gray-500 dark:text-gray-400 text-sm">Total registered users breakdown</p>
        </div>
      </div>
