// --- Main App Logic ---

export default function App() {
  // State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [authView, setAuthView] = useState<'login' | 'signup'>('login');

  // Theme State
  const [isDarkMode, setIsDarkMode] = useState(false);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  // Simulated Data Store (In real app, fetch from backend)
  const [users, setUsers] = useState<User[]>(MOCK_USERS);
  const [batches, setBatches] = useState<Batch[]>(MOCK_BATCHES);
  const [tasks, setTasks] = useState<Task[]>(MOCK_TASKS);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>(MOCK_ATTENDANCE);
  const [submissions, setSubmissions] = useState<Submission[]>(MOCK_SUBMISSIONS);
  const [payments, setPayments] = useState<Payment[]>(MOCK_PAYMENTS);
  const [placements, setPlacements] = useState<Placement[]>(MOCK_PLACEMENTS);

  // Handlers
  const handleLogin = (role: UserRole, email: string) => {
    // Check if user exists with this email and role
    const existingUser = users.find(u => u.email === email && u.role === role);

    if (existingUser) {
      setCurrentUser(existingUser);
      setActiveTab('dashboard'); 
    } else {
      // For demo purposes, auto-create if not exists or simulate login with a new user
      // In a real app, this would show an error "Invalid credentials"
      const newUser: User = {
        id: `u${Date.now()}`,
        name: email.split('@')[0],
        email: email,
        role: role,
        avatar: `https://ui-avatars.com/api/?name=${email.split('@')[0]}&background=random`
      };
      // Note: We don't add to users array here to keep mock data clean, but in a real app this is an error case.
      // However, for this demo UX, let's allow it so user can see the dashboard immediately.
      setCurrentUser(newUser);
      setActiveTab('dashboard');
    }
  };

  const handleSignup = (userData: Partial<User>) => {
    const newUser: User = {
      id: `u${Date.now()}`,
      name: userData.name!,
      email: userData.email!,
      role: userData.role!,
      avatar: `https://ui-avatars.com/api/?name=${userData.name}&background=random`
    };
    setUsers([...users, newUser]);
    setCurrentUser(newUser);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setAuthView('login');
  };

  const handleDeleteUser = (id: string) => {
    setUsers(prev => prev.filter(u => u.id !== id));
  };

  const handleMarkAttendance = (batchId: string, studentId: string, status: 'PRESENT' | 'ABSENT') => {
    // Remove existing for today if exists to allow toggle
    const today = new Date().toISOString().split('T')[0];
    const newRecord: AttendanceRecord = {
      id: `a${Date.now()}`,
      batchId,
      studentId,
      date: today,
      status
    };

    setAttendance(prev => {
      const filtered = prev.filter(a => !(a.studentId === studentId && a.date === today && a.batchId === batchId));
      return [...filtered, newRecord];
    });
  };

  const handleAddTask = (task: Task) => {
    setTasks(prev => [...prev, task]);
  };

  const handleAddBatch = (batch: Batch) => {
    setBatches(prev => [...prev, batch]);
  };

  const handleAddAttendance = (record: AttendanceRecord) => {
    setAttendance(prev => [...prev, record]);
  };

  const handleAddPayment = (payment: Payment) => {
    setPayments(prev => [...prev, payment]);
  };

  const handleAddPlacement = (placement: Placement) => {
    setPlacements(prev => [...prev, placement]);
  };

  const handleGradeSubmission = (submissionId: string, grade: number, feedback: string) => {
     setSubmissions(prev => prev.map(s => 
        s.id === submissionId ? { ...s, grade, feedback } : s
     ));
  };

  // Rendering Layout based on role and tab
  const renderContent = () => {
    if (!currentUser) return null;

    if (currentUser.role === UserRole.ADMIN) {
      switch (activeTab) {
        case 'dashboard':
          return <AdminDashboard users={users} batches={batches} attendance={attendance} />;
        case 'users':
          return <UserManagement users={users} onDeleteUser={handleDeleteUser} />;
        case 'batches':
          return <AdminBatchesView batches={batches} users={users} onAddBatch={handleAddBatch} />;
        case 'admin_tasks':
           return <AdminTasksView tasks={tasks} batches={batches} user={currentUser} onAddTask={handleAddTask} />;
        case 'admin_attendance':
           return <AdminAttendanceView attendance={attendance} users={users} batches={batches} onAddAttendance={handleAddAttendance} />;
        case 'payments':
           return <AdminPaymentsView payments={payments} users={users} onAddPayment={handleAddPayment} />;
        case 'placements':
           return <AdminPlacementsView placements={placements} users={users} onAddPlacement={handleAddPlacement} />;
        default: return null;
      }
    }

    if (currentUser.role === UserRole.TRAINER) {
       switch(activeTab) {
         case 'dashboard':
           return <TrainerDashboard user={currentUser} batches={batches} tasks={tasks} submissions={submissions} />;
         case 'attendance':
           return <TrainerAttendanceView 
              user={currentUser} 
              batches={batches} 
              users={users} 
              attendance={attendance} 
              onMarkAttendance={handleMarkAttendance} 
            />;
         case 'tasks':
            return <TrainerTasksView 
              user={currentUser} 
              batches={batches} 
              tasks={tasks} 
              onAddTask={handleAddTask} 
            />;
         case 'grading':
            return <TrainerGradingView 
               user={currentUser}
               tasks={tasks}
               submissions={submissions}
               users={users}
               onGrade={handleGradeSubmission}
            />;
       }
    }

    if (currentUser.role === UserRole.STUDENT) {
       switch(activeTab) {
          case 'dashboard':
             return <StudentDashboard 
               user={currentUser} 
               batches={batches} 
               tasks={tasks} 
               attendance={attendance}
               submissions={submissions}
             />;
          case 'tasks':
             return <StudentTasksView
               user={currentUser}
               batches={batches}
               tasks={tasks}
               submissions={submissions}
             />;
          case 'attendance':
             return <StudentAttendanceView
               user={currentUser}
               attendance={attendance}
               batches={batches}
             />;
          case 'payments':
             return <StudentPaymentsView
               user={currentUser}
               payments={payments}
             />;
          case 'placements':
             return <StudentPlacementsView
               user={currentUser}
               placements={placements}
             />;
       }
    }
  };

  const themeProps = { isDark: isDarkMode, toggle: toggleTheme };

  if (!currentUser) {
    return authView === 'login' 
      ? <LoginPage onLogin={handleLogin} onSwitchToSignup={() => setAuthView('signup')} themeProps={themeProps} />
      : <SignupPage onSignup={handleSignup} onSwitchToLogin={() => setAuthView('login')} themeProps={themeProps} />;
  }

  return (
    <Layout 
      user={currentUser} 
      onLogout={handleLogout}
      activeTab={activeTab}
      setActiveTab={setActiveTab}
      themeProps={themeProps}
    >
      {renderContent()}
    </Layout>
  );
}

