const RoleBadge = ({ role }: { role: UserRole | null }) => {
  if (!role) return null;

  const config = {
    [UserRole.ADMIN]: { bg: 'bg-red-50 dark:bg-red-900/20', text: 'text-red-700 dark:text-red-300', label: 'Administrator' },
    [UserRole.TRAINER]: { bg: 'bg-purple-50 dark:bg-purple-900/20', text: 'text-purple-700 dark:text-purple-300', label: 'Trainer' },
    [UserRole.STUDENT]: { bg: 'bg-blue-50 dark:bg-blue-900/20', text: 'text-blue-700 dark:text-blue-300', label: 'Student' },
  };

  const current = config[role];

  return (
    <div className={`mt-2 flex items-center justify-center p-2 rounded-lg border border-dashed ${current.bg} border-opacity-50 border-${current.text.split('-')[1]}-200 animate-in fade-in slide-in-from-top-2`}>
       <span className={`text-xs font-bold uppercase tracking-wide ${current.text}`}>
         Detected Role: {current.label}
       </span>
    </div>
  );
};

