      {aiInsight && (
        <div className="bg-indigo-50 dark:bg-indigo-900/30 border border-indigo-100 dark:border-indigo-800 p-4 rounded-xl flex gap-3 animate-fade-in">
          <BrainCircuit className="w-6 h-6 text-indigo-600 dark:text-indigo-400 flex-shrink-0 mt-1" />
          <div>
            <h4 className="font-semibold text-indigo-800 dark:text-indigo-300">AI Executive Summary</h4>
            <p className="text-indigo-700 dark:text-indigo-200 mt-1 text-sm leading-relaxed">{aiInsight}</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
