const TrainerDashboard = ({ user, batches, tasks, submissions }: { user: User, batches: Batch[], tasks: Task[], submissions: Submission[] }) => {
  const myBatches = batches.filter(b => b.trainerId === user.id);
  const myBatchIds = myBatches.map(b => b.id);
  const myTasks = tasks.filter(t => myBatchIds.includes(t.batchId));
  const myTaskIds = myTasks.map(t => t.id);

  // Calculate unique students across all batches
  const studentIds = new Set(myBatches.flatMap(b => b.studentIds));
  const totalStudents = studentIds.size;

  // Count ungraded submissions for my tasks
  const pendingGrading = submissions.filter(s => myTaskIds.includes(s.taskId) && !s.grade).length;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-2xl font-bold text-gray-800 dark:text-white">Trainer Dashboard</h2>
          <p className="text-gray-500 dark:text-gray-400 mt-1">Manage your classes and students</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="My Batches" value={myBatches.length} icon={Calendar} color="bg-indigo-500" />
        <StatCard label="Total Students" value={totalStudents} icon={Users} color="bg-purple-500" />
        <StatCard label="Active Tasks" value={myTasks.length} icon={ClipboardList} color="bg-blue-500" />
        <StatCard label="Pending Grades" value={pendingGrading} icon={Award} color="bg-orange-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white dark:bg-gray-800 p-6 rounded-xl shadow-sm border border-gray-200 dark:border-gray-700">
           <h3 className="font-bold text-gray-800 dark:text-white mb-4">My Schedule</h3>
           <div className="space-y-3">
             {myBatches.map(batch => (
                <div key={batch.id} className="flex items-center justify-between p-3 bg-gray-50 dark:bg-gray-700/50 rounded-lg border border-gray-100 dark:border-gray-700">
                   <div>
                      <p className="font-bold text-gray-700 dark:text-gray-200">{batch.name}</p>
                      <p className="text-sm text-gray-500 dark:text-gray-400">{batch.course}</p>
                   </div>
                   <div className="text-right">
                      <span className="bg-indigo-100 dark:bg-indigo-900/30 text-indigo-700 dark:text-indigo-300 text-xs px-2 py-1 rounded font-medium">{batch.schedule}</span>
                   </div>
                </div>
             ))}
           </div>
        </div>
      </div>
    </div>
  );
};

const TrainerAttendanceView = ({ 
  user, batches, users, attendance, onMarkAttendance 
}: { 
