           <h3 className="font-semibold text-gray-700 dark:text-gray-200">Date: {new Date().toLocaleDateString()}</h3>
           <span className="text-sm text-gray-500 dark:text-gray-400">{batchStudents.length} Students Enrolled</span>
        </div>
        <div className="divide-y divide-gray-100 dark:divide-gray-700">
          {batchStudents.map(student => {
             const record = attendance.find(a => 
