               type="text"
               required
               value={formData.name}
               onChange={handleChange}
               className="focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 border-gray-300 dark:border-gray-600 rounded-lg p-2.5 border sm:text-sm bg-white dark:bg-gray-700 dark:text-white dark:placeholder-gray-400"
               placeholder="John Doe"
             />
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Email Address</label>
           <div className="mt-1 relative rounded-md shadow-sm">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Mail className="h-5 w-5 text-gray-400" />
             </div>
             <input
               name="email"
               type="email"
               required
               value={formData.email}
               onChange={handleChange}
               className="focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 border-gray-300 dark:border-gray-600 rounded-lg p-2.5 border sm:text-sm bg-white dark:bg-gray-700 dark:text-white dark:placeholder-gray-400"
               placeholder="john@example.com"
             />
          </div>
        </div>

        <div>
           <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Register As</label>
           <div className="mt-1 relative rounded-md shadow-sm">
             <select
               name="role"
               value={formData.role}
               onChange={handleChange}
               className="block w-full pl-3 pr-10 py-2.5 text-base border-gray-300 dark:border-gray-600 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-lg border bg-white dark:bg-gray-700 dark:text-white"
             >
               <option value={UserRole.STUDENT}>Student</option>
               <option value={UserRole.TRAINER}>Trainer</option>
               <option value={UserRole.ADMIN}>Administrator</option>
             </select>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Password</label>
               <input
                 name="password"
                 type="password"
                 required
                 value={formData.password}
                 onChange={handleChange}
                 className="mt-1 focus:ring-indigo-500 focus:border-indigo-500 block w-full border-gray-300 dark:border-gray-600 rounded-lg p-2.5 border sm:text-sm bg-white dark:bg-gray-700 dark:text-white dark:placeholder-gray-400"
                 placeholder="••••••••"
