            </div>
             <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Confirm Password</label>
               <input
                 name="confirmPassword"
                 type="password"
                 required
                 value={formData.confirmPassword}
                 onChange={handleChange}
                 className="mt-1 focus:ring-indigo-500 focus:border-indigo-500 block w-full border-gray-300 dark:border-gray-600 rounded-lg p-2.5 border sm:text-sm bg-white dark:bg-gray-700 dark:text-white dark:placeholder-gray-400"
                 placeholder="••••••••"
               />
            </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Phone Number</label>
           <div className="mt-1 relative rounded-md shadow-sm">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Phone className="h-5 w-5 text-gray-400" />
             </div>
             <input
               name="phone"
               type="tel"
               required
               value={formData.phone}
               onChange={handleChange}
               className="focus:ring-indigo-500 focus:border-indigo-500 block w-full pl-10 border-gray-300 dark:border-gray-600 rounded-lg p-2.5 border sm:text-sm bg-white dark:bg-gray-700 dark:text-white dark:placeholder-gray-400"
               placeholder="+1 (555) 987-6543"
             />
          </div>
        </div>

        {formData.role === UserRole.STUDENT && (
           <div className="animate-in fade-in slide-in-from-top-2">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Select Course</label>
              <select
                 name="courseOrExpertise"
                 value={formData.courseOrExpertise}
                 onChange={handleChange}
                 className="mt-1 block w-full pl-3 pr-10 py-2.5 text-base border-gray-300 dark:border-gray-600 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-lg border bg-white dark:bg-gray-700 dark:text-white"
              >
                <option value="">Select a course...</option>
                <option value="Java Full Stack">Java Full Stack</option>
                <option value="Python Data Science">Python Data Science</option>
                <option value="React Frontend">React Frontend</option>
                <option value="DevOps Engineering">DevOps Engineering</option>
              </select>
           </div>
        )}

        {formData.role === UserRole.TRAINER && (
           <div className="animate-in fade-in slide-in-from-top-2">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Primary Expertise</label>
               <input
                 name="courseOrExpertise"
                 type="text"
                 value={formData.courseOrExpertise}
                 onChange={handleChange}
                 className="mt-1 focus:ring-indigo-500 focus:border-indigo-500 block w-full border-gray-300 dark:border-gray-600 rounded-lg p-2.5 border sm:text-sm bg-white dark:bg-gray-700 dark:text-white dark:placeholder-gray-400"
                 placeholder="e.g. Artificial Intelligence"
               />
           </div>
        )}

        <div className="pt-2">
          <button
            type="submit"
            className="w-full flex justify-center py-3 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-colors"
          >
            Create Account
          </button>
        </div>

        <div className="mt-4 text-center">
            <button 
                type="button"
                onClick={onSwitchToLogin}
                className="text-sm font-medium text-indigo-600 dark:text-indigo-400 hover:text-indigo-500 flex items-center justify-center w-full gap-1"
            >
                <ArrowLeft className="w-4 h-4" /> Back to Sign In
            </button>
        </div>
      </form>
    </AuthLayout>
  );
};

export default function App() {
  // Initialize from localStorage to persist state across refreshes
  const [isLogin, setIsLogin] = useState(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('isLogin') === 'true';
    }
    return false;
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('theme');
      if (saved) return saved === 'dark';
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    }
    return false;
  });

  // Persist isLogin state
  useEffect(() => {
    localStorage.setItem('isLogin', String(isLogin));
  }, [isLogin]);

  // Persist Theme state
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const themeProps = { isDark: isDarkMode, toggle: toggleTheme };

  const handleSignup = (user: Partial<User>) => {
    console.log('User signed up:', user);
    alert('Account created! (Simulation)');
    setIsLogin(true);
  };

  if (isLogin) {
    return (
      <AuthLayout title="Sign In" subtitle="Welcome back to EduManage" themeProps={themeProps}>
        <div className="text-center">
          <p className="text-gray-600 dark:text-gray-300 mb-4">Login functionality is not implemented in this demo.</p>
          <button 
            type="button"
            onClick={() => setIsLogin(false)}
            className="text-indigo-600 hover:text-indigo-500 font-medium"
          >
            Back to Sign Up
          </button>
        </div>
      </AuthLayout>
    );
  }

  return (
    <SignupPage 
      onSignup={handleSignup} 
      onSwitchToLogin={() => setIsLogin(true)} 
      themeProps={themeProps} 
    />
  );
}

export enum UserRole {
  ADMIN = 'ADMIN',
  TRAINER = 'TRAINER',
  STUDENT = 'STUDENT'
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar?: string;
  courseOrExpertise?: string; // Course for student, Expertise for trainer
}

export interface Batch {
  id: string;
  name: string;
  trainerId: string;
  studentIds: string[];
  schedule: string;
  course: string;
}

export interface AttendanceRecord {
  id: string;
  batchId: string;
  studentId: string;
  date: string;
  status: 'PRESENT' | 'ABSENT' | 'LATE';
}

export interface Task {
  id: string;
  batchId: string;
  title: string;
  description: string;
  dueDate: string;
  assignedBy: string; // Trainer ID
}

export interface Submission {
  id: string;
  taskId: string;
  studentId: string;
  submittedAt: string;
  grade?: number; // 0-100
  feedback?: string;
}

export interface Payment {
  id: string;
  studentId: string;
  amount: number;
  date: string;
  status: 'PAID' | 'PENDING' | 'OVERDUE';
  type: 'TUITION' | 'EXAM' | 'OTHER';
}

export interface Placement {
