        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <StatCard 
            title="Total Students" 
            value={totalStudents} 
            icon={Users} 
            trend="+12%" 
            color="bg-blue-500" 
          />
          <StatCard 
            title="Total Trainers" 
            value={totalTrainers} 
            icon={BookOpen} 
            trend="+2%" 
            color="bg-indigo-500" 
          />
          <StatCard 
            title="Active Batches" 
            value={batches.length} 
            icon={CalendarCheck} 
            trend="+5%" 
            color="bg-purple-500" 
          />
          <StatCard 
            title="Avg Attendance" 
            value="87%" 
            icon={TrendingUp} 
            trend="+3.4%" 
            color="bg-emerald-500" 
          />
        </div>

        {/* Recent Activity Section could go here */}
      </div>
