export default function App() {
  const [authView, setAuthView] = useState<'LOGIN' | 'SIGNUP'>('SIGNUP');

  // Initialize states from localStorage
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    if (typeof window !== 'undefined') {
      const savedUser = localStorage.getItem('currentUser');
      return savedUser ? JSON.parse(savedUser) : null;
    }
    return null;
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('theme');
      if (saved) return saved === 'dark';
      return window.matchMedia('(prefers-color-scheme: dark)').matches;
    }
    return false;
  });

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('currentUser', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [currentUser]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleTheme = () => setIsDarkMode(!isDarkMode);
  const themeProps = { isDark: isDarkMode, toggle: toggleTheme };

  const handleSignup = (userData: Partial<User>) => {
    // Create a mock user
    const newUser: User = {
      id: `u${Date.now()}`,
      name: userData.name!,
      email: userData.email!,
      role: userData.role!,
      courseOrExpertise: userData.courseOrExpertise,
      avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(userData.name!)}&background=random`
    };

    // In a real app, this would hit an API
    console.log('User signed up:', newUser);
    setCurrentUser(newUser);
  };

  const handleLogin = (email: string) => {
    // Mock Login: Check against mock users or default admin logic
    let user = MOCK_USERS.find(u => u.email === email);

    // Special case for the admin email mentioned in prompt
    if (email === 'sakshipawar5840@gmail.com') {
        user = {
            id: 'admin-special',
            name: 'Sakshi Pawar',
            email: email,
            role: UserRole.ADMIN,
            avatar: 'https://ui-avatars.com/api/?name=Sakshi+Pawar&background=random'
        };
    }

    if (user) {
        setCurrentUser(user);
    } else {
        // Create a temporary session user for demo if email not in mock DB
        const tempUser: User = {
            id: `temp-${Date.now()}`,
            name: email.split('@')[0],
            email: email,
            role: UserRole.STUDENT, // Default to student for unknown emails
            avatar: `https://ui-avatars.com/api/?name=${email.split('@')[0]}`
        }
        setCurrentUser(tempUser);
        // Alert only for clarity in demo
        // alert(`Logged in as ${tempUser.role} (Mock)`);
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setAuthView('LOGIN');
  };

  // Rendering Logic
  if (!currentUser) {
     if (authView === 'LOGIN') {
         return <LoginPage onLogin={handleLogin} onSwitchToSignup={() => setAuthView('SIGNUP')} themeProps={themeProps} />;
     } else {
         return <SignupPage onSignup={handleSignup} onSwitchToLogin={() => setAuthView('LOGIN')} themeProps={themeProps} />;
     }
  }

  // Dashboard Routing
  if (currentUser.role === UserRole.ADMIN) {
      return <AdminDashboard user={currentUser} onLogout={handleLogout} themeProps={themeProps} />;
  }

  if (currentUser.role === UserRole.TRAINER) {
      return <TrainerDashboard user={currentUser} onLogout={handleLogout} themeProps={themeProps} />;
  }

  // Fallback for Student (using basic layout for now or placeholder)
  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 flex flex-col items-center justify-center p-4">
        <ThemeToggle {...themeProps} />
        <h1 className="text-2xl font-bold text-gray-900 dark:text-white mt-4">Student Dashboard</h1>
        <p className="text-gray-600 dark:text-gray-400 mt-2">Welcome, {currentUser.name}. Student view is under construction.</p>
        <button onClick={handleLogout} className="mt-4 px-4 py-2 bg-indigo-600 text-white rounded hover:bg-indigo-700">Sign Out</button>
    </div>
  );
}

