} from 'lucide-react';
import { MOCK_USERS, MOCK_BATCHES, MOCK_PAYMENTS, MOCK_PLACEMENTS, MOCK_TASKS, MOCK_ATTENDANCE } from './constants';

interface AdminDashboardProps {
  user: User;
